
.status-icon {
  --icon-color: var(--icon-main);

  display: inline-grid;
  place-items: center;
  width: 24px;
  height: 24px;
  flex: 0 0 auto;
  color: var(--icon-color);
  filter: drop-shadow(0 1px 2px rgba(0, 0, 0, 0.36));
}

.status-icon svg {
  width: 100%;
  height: 100%;
  stroke-width: 1.8;
}

.soft-fill {
  fill: currentColor;
  opacity: 0.14;
  stroke: none;
}

.size-sm {
  width: 18px;
  height: 18px;
}

.size-md {
  width: 24px;
  height: 24px;
}

.size-lg {
  width: 36px;
  height: 36px;
}

.size-badge {
  width: 54px;
  height: 54px;
}

.size-badge svg {
  stroke-width: 2;
}

.tone-main {
  --icon-color: var(--icon-main);
}

.tone-muted {
  --icon-color: var(--icon-muted);
}

.tone-blue {
  --icon-color: var(--icon-blue);
}

.tone-cyan {
  --icon-color: var(--icon-cyan);
}

.tone-crimson {
  --icon-color: var(--icon-crimson);
}

.tone-amber {
  --icon-color: var(--icon-amber);
}

.tone-danger {
  --icon-color: var(--icon-danger);
}

.tone-dark {
  --icon-color: var(--icon-dark);
}

.is-glowing {
  filter: drop-shadow(0 0 8px color-mix(in srgb, var(--icon-color) 48%, transparent));
}

.is-dimmed {
  opacity: 0.55;
}
