
.est-status {
  --panel-bg: #10222a;
  --panel-bg-2: #1d3038;
  --panel-line: rgba(221, 235, 238, 0.2);
  --panel-line-strong: rgba(231, 241, 242, 0.34);
  --text-main: #edf2f2;
  --text-soft: #aebcc0;
  --text-muted: #7f929a;
  --drawer-bg: #eeecea;
  --drawer-line: rgba(31, 47, 55, 0.16);
  --drawer-text: #20313a;
  --icon-main: #e8edf0;
  --icon-muted: #91a4ad;
  --icon-blue: #67b7f7;
  --icon-cyan: #75d8e6;
  --icon-crimson: #d66b70;
  --icon-amber: #d9a84d;
  --icon-danger: #b8474f;
  --icon-dark: #20313a;
  --accent: var(--icon-blue);

  width: 100%;
  max-width: 720px;
  margin: 0 auto;
  color: var(--text-main);
  font-family:
    ui-serif,
    'Noto Serif SC',
    'Songti SC',
    serif;
  line-height: 1.42;
}

.san-amber {
  --accent: var(--icon-amber);
}

.san-danger {
  --accent: var(--icon-danger);
}

.san-collapse {
  --accent: var(--icon-danger);
}

.san-collapse .hero-card,
.san-collapse .san-button {
  animation: sanPulse 1.7s ease-in-out infinite;
}

.status-frame {
  position: relative;
  overflow: hidden;
  padding: 16px;
  border: 1px solid rgba(215, 231, 236, 0.22);
  border-radius: 22px;
  background:
    radial-gradient(circle at 18% 0%, rgba(103, 183, 247, 0.2), transparent 34%),
    linear-gradient(145deg, #0a1a20 0%, #152830 52%, #08171d 100%);
  box-shadow:
    inset 0 1px 0 rgba(255, 255, 255, 0.12),
    0 18px 48px rgba(1, 10, 14, 0.42);
}

.status-frame::before {
  content: '';
  position: absolute;
  inset: 0;
  pointer-events: none;
  background-image:
    linear-gradient(rgba(255, 255, 255, 0.035) 1px, transparent 1px),
    linear-gradient(90deg, rgba(255, 255, 255, 0.025) 1px, transparent 1px);
  background-size: 22px 22px;
  mask-image: linear-gradient(to bottom, rgba(0, 0, 0, 0.8), transparent);
}

.status-header,
.hero-card,
.scene-grid,
.todo-card,
.character-stack,
.detail-panel,
.modal-layer {
  position: relative;
  z-index: 1;
}

.status-header {
  display: grid;
  grid-template-columns: auto 1fr auto;
  gap: 12px;
  align-items: center;
  margin-bottom: 14px;
}

.brand-mark {
  display: grid;
  place-items: center;
}

.brand-copy {
  min-width: 0;
}

.eyebrow,
.field-label,
.section-title small,
.character-main span,
.san-readout span,
.scene-cell span,
.record-block span,
.metric-copy span {
  color: var(--text-soft);
  font-family:
    ui-sans-serif,
    'Microsoft YaHei',
    sans-serif;
  font-size: 11px;
  letter-spacing: 0;
}

.brand-copy h1 {
  margin: 2px 0 0;
  font-size: 24px;
  font-weight: 800;
  letter-spacing: 0;
  text-shadow: 0 2px 10px rgba(0, 0, 0, 0.45);
}

button {
  font: inherit;
}

.icon-button,
.panel-close {
  display: grid;
  place-items: center;
  width: 44px;
  height: 44px;
  border: 1px solid var(--panel-line);
  border-radius: 50%;
  color: inherit;
  background: rgba(255, 255, 255, 0.08);
  box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.12);
  cursor: pointer;
}

.san-button {
  position: relative;
}

.san-button::after {
  content: '';
  position: absolute;
  inset: 8px;
  border: 1px solid color-mix(in srgb, var(--accent) 42%, transparent);
  border-radius: inherit;
  opacity: 0;
}

.san-amber .san-button::after,
.san-danger .san-button::after,
.san-collapse .san-button::after {
  opacity: 1;
}

.hero-card,
.todo-card,
.scene-cell,
.character-row,
.quick-actions button,
.text-link {
  border: 1px solid var(--panel-line);
  color: inherit;
  background: rgba(255, 255, 255, 0.075);
  box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.1);
  cursor: pointer;
}

.hero-card:active,
.todo-card:active,
.scene-cell:active,
.character-row:active,
.quick-actions button:active,
.icon-button:active,
.panel-close:active {
  transform: translateY(1px);
}

.hero-card {
  width: 100%;
  display: grid;
  grid-template-columns: minmax(0, 1fr) auto;
  gap: 12px;
  align-items: center;
  padding: 14px;
  border-radius: 18px;
  text-align: left;
  background:
    linear-gradient(120deg, rgba(235, 243, 245, 0.14), rgba(92, 141, 154, 0.08)),
    rgba(255, 255, 255, 0.055);
}

.hero-identity {
  display: flex;
  gap: 12px;
  align-items: center;
  min-width: 0;
}

.badge-shell,
.avatar,
.todo-icon {
  display: grid;
  place-items: center;
  flex: 0 0 auto;
  border: 1px solid var(--panel-line-strong);
  background: rgba(255, 255, 255, 0.08);
  box-shadow:
    inset 0 1px 0 rgba(255, 255, 255, 0.16),
    0 10px 20px rgba(0, 0, 0, 0.18);
}

.badge-shell {
  width: 64px;
  height: 64px;
  border-radius: 18px;
}

.hero-identity strong,
.character-main strong,
.san-readout strong {
  display: block;
  overflow-wrap: anywhere;
  font-size: 24px;
  line-height: 1.1;
}

.hero-identity span:last-child,
.character-main p,
.summary-text,
.todo-card p,
.equipment-item p,
.equipment-item span,
.record-block p,
.san-panel p {
  margin: 0;
  color: var(--text-soft);
  font-family:
    ui-sans-serif,
    'Microsoft YaHei',
    sans-serif;
  font-size: 13px;
}

.san-readout {
  width: 118px;
  text-align: right;
}

.san-readout strong {
  color: var(--accent);
  font-family: Georgia, serif;
  font-size: 22px;
}

.meter-track {
  width: 100%;
  height: 7px;
  overflow: hidden;
  border-radius: 999px;
  background: rgba(6, 17, 22, 0.54);
  box-shadow: inset 0 1px 2px rgba(0, 0, 0, 0.45);
}

.meter-track span {
  display: block;
  height: 100%;
  border-radius: inherit;
  background: linear-gradient(90deg, var(--accent), color-mix(in srgb, var(--accent) 68%, white));
  box-shadow: 0 0 12px color-mix(in srgb, var(--accent) 52%, transparent);
}

.scene-grid {
  display: grid;
  grid-template-columns: 0.85fr 1.3fr 0.85fr;
  gap: 8px;
  margin-top: 10px;
}

.scene-cell {
  display: grid;
  gap: 4px;
  align-content: start;
  min-width: 0;
  min-height: 94px;
  padding: 12px;
  border-radius: 15px;
  text-align: left;
}

.scene-cell strong {
  display: -webkit-box;
  overflow: hidden;
  font-size: 15px;
  line-height: 1.25;
  -webkit-box-orient: vertical;
  -webkit-line-clamp: 2;
}

.todo-card {
  width: 100%;
  display: grid;
  grid-template-columns: auto minmax(0, 1fr) auto;
  gap: 12px;
  align-items: center;
  margin-top: 10px;
  padding: 12px;
  border-radius: 16px;
  text-align: left;
}

.todo-icon {
  width: 52px;
  height: 52px;
  border-radius: 16px;
}

.todo-card p,
.summary-text {
  display: -webkit-box;
  overflow: hidden;
  -webkit-box-orient: vertical;
  -webkit-line-clamp: 2;
}

.action-summary {
  color: color-mix(in srgb, var(--text-soft) 86%, var(--accent));
}

.character-stack {
  display: grid;
  gap: 10px;
  margin-top: 14px;
}

.section-title {
  display: flex;
  align-items: baseline;
  justify-content: space-between;
  gap: 12px;
  padding: 0 2px;
  font-weight: 800;
}

.character-list-meta,
.character-group-title {
  display: flex;
  align-items: center;
  gap: 8px;
  color: var(--text-soft);
  font-family:
    ui-sans-serif,
    'Microsoft YaHei',
    sans-serif;
  font-size: 12px;
}

.character-list-meta {
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
}

.character-list-meta span {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 6px;
  min-height: 34px;
  border: 1px solid rgba(255, 255, 255, 0.11);
  border-radius: 999px;
  background: rgba(255, 255, 255, 0.055);
}

.character-group-title {
  margin-top: 4px;
  padding: 0 4px;
  font-weight: 700;
}

.empty-card {
  display: flex;
  align-items: center;
  gap: 10px;
  min-height: 58px;
  padding: 12px;
  border: 1px dashed rgba(221, 235, 238, 0.2);
  border-radius: 16px;
  background: rgba(255, 255, 255, 0.04);
}

.empty-card p {
  margin: 0;
  color: var(--text-soft);
  font-family:
    ui-sans-serif,
    'Microsoft YaHei',
    sans-serif;
  font-size: 13px;
}

.character-card {
  overflow: hidden;
  border: 1px solid var(--panel-line);
  border-radius: 17px;
  background: rgba(255, 255, 255, 0.055);
  box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.1);
}

.female-card {
  background: linear-gradient(120deg, rgba(214, 107, 112, 0.12), rgba(255, 255, 255, 0.05));
}

.character-row {
  width: 100%;
  display: grid;
  grid-template-columns: auto minmax(0, 1fr) auto;
  gap: 12px;
  align-items: center;
  min-height: 76px;
  padding: 12px;
  border: 0;
  border-radius: 0;
  text-align: left;
  background: transparent;
}

.avatar {
  width: 54px;
  height: 54px;
  border-radius: 16px;
}

.knight-avatar {
  background: rgba(103, 183, 247, 0.12);
}

.female-avatar {
  background: rgba(214, 107, 112, 0.12);
}

.character-main {
  min-width: 0;
}

.character-main strong {
  font-size: 20px;
}

.character-main p {
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.character-meta {
  display: grid;
  justify-items: end;
  gap: 4px;
  color: var(--text-soft);
  font-family:
    ui-sans-serif,
    'Microsoft YaHei',
    sans-serif;
  font-size: 12px;
}

.character-meta span {
  white-space: nowrap;
}

.accordion-body {
  display: grid;
  gap: 10px;
  padding: 0 12px 12px;
}

.detail-grid {
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 8px;
}

.metric-row {
  display: grid;
  grid-template-columns: auto auto auto minmax(66px, 1fr);
  gap: 8px;
  align-items: center;
  padding: 9px;
  border-radius: 12px;
  background: rgba(214, 107, 112, 0.1);
}

.metric-row strong {
  color: var(--icon-crimson);
}

.quick-actions {
  display: grid;
  grid-template-columns: repeat(3, minmax(0, 1fr));
  gap: 8px;
}

.quick-actions button,
.text-link {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 6px;
  min-height: 44px;
  padding: 9px 10px;
  border-radius: 12px;
  font-family:
    ui-sans-serif,
    'Microsoft YaHei',
    sans-serif;
  font-size: 13px;
}

.text-link {
  justify-self: start;
  color: var(--text-main);
  background: rgba(255, 255, 255, 0.06);
}

.detail-panel {
  margin-top: 14px;
  overflow: hidden;
  border-radius: 22px 22px 16px 16px;
  color: var(--drawer-text);
  background:
    linear-gradient(180deg, rgba(255, 255, 255, 0.92), rgba(231, 232, 230, 0.96)),
    var(--drawer-bg);
  box-shadow:
    inset 0 1px 0 rgba(255, 255, 255, 0.85),
    0 18px 34px rgba(0, 0, 0, 0.24);
}

.panel-handle {
  width: 54px;
  height: 5px;
  margin: 10px auto 2px;
  border-radius: 999px;
  background: rgba(32, 49, 58, 0.35);
}

.panel-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 12px;
  padding: 14px 16px 10px;
}

.panel-header .field-label {
  color: rgba(32, 49, 58, 0.62);
}

.panel-header h2 {
  margin: 0;
  color: var(--drawer-text);
  font-size: 22px;
  line-height: 1.18;
}

.panel-close {
  border-color: var(--drawer-line);
  background: rgba(255, 255, 255, 0.62);
}

.panel-content {
  display: grid;
  gap: 10px;
  max-height: min(560px, 130vw);
  overflow: auto;
  padding: 0 16px 16px;
}

.mobility-head,
.san-panel,
.female-overview-card,
.relation-card {
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 12px;
  border: 1px solid var(--drawer-line);
  border-radius: 16px;
  background: rgba(255, 255, 255, 0.46);
}

.mobility-head div,
.san-panel,
.female-overview-card div,
.relation-card div {
  display: grid;
}

.mobility-head span,
.female-overview-card span,
.relation-card span {
  color: rgba(32, 49, 58, 0.62);
}

.female-overview-card,
.relation-card {
  background:
    linear-gradient(120deg, rgba(214, 107, 112, 0.13), rgba(255, 255, 255, 0.52)),
    rgba(255, 255, 255, 0.46);
}

.female-overview-card strong,
.relation-card strong {
  color: var(--drawer-text);
  font-size: 20px;
}

.drawer-action-grid {
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 8px;
}

.drawer-action-grid button {
  display: flex;
  align-items: center;
  gap: 8px;
  min-height: 48px;
  padding: 10px;
  border: 1px solid var(--drawer-line);
  border-radius: 14px;
  color: var(--drawer-text);
  background: rgba(255, 255, 255, 0.52);
  font-family:
    ui-sans-serif,
    'Microsoft YaHei',
    sans-serif;
  cursor: pointer;
}

.drawer-action-grid button:active {
  transform: translateY(1px);
}

.mobility-support {
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 8px;
}

.mobility-support > :deep(.record-block):last-child:nth-child(odd) {
  grid-column: 1 / -1;
}

.panel-footer {
  display: flex;
  justify-content: center;
  padding-top: 2px;
}

.drawer-back {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 8px;
  min-height: 44px;
  width: 100%;
  padding: 10px 12px;
  border: 1px solid var(--drawer-line);
  border-radius: 14px;
  color: var(--drawer-text);
  background: rgba(255, 255, 255, 0.56);
  font-family:
    ui-sans-serif,
    'Microsoft YaHei',
    sans-serif;
  cursor: pointer;
}

.drawer-back:active {
  transform: translateY(1px);
}

.appearance-grid {
  display: grid;
  gap: 10px;
}

.body-panel {
  gap: 9px;
}

.body-section {
  overflow: hidden;
  border: 1px solid rgba(214, 107, 112, 0.24);
  border-radius: 16px;
  background:
    linear-gradient(135deg, rgba(214, 107, 112, 0.1), rgba(255, 255, 255, 0.48)),
    rgba(255, 255, 255, 0.48);
}

.body-section summary {
  display: grid;
  grid-template-columns: auto 1fr auto;
  gap: 8px;
  align-items: center;
  min-height: 52px;
  padding: 10px 12px;
  color: var(--drawer-text);
  cursor: pointer;
  list-style: none;
}

.body-section summary::-webkit-details-marker {
  display: none;
}

.body-section summary span {
  font-size: 15px;
  font-weight: 800;
}

.body-section summary small {
  color: rgba(32, 49, 58, 0.58);
  font-family:
    ui-sans-serif,
    'Microsoft YaHei',
    sans-serif;
  font-size: 12px;
}

.body-section[open] {
  box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.72);
}

.body-section > :deep(.record-block) {
  margin: 0 10px 10px;
  background: rgba(255, 255, 255, 0.58);
}

.metric-list {
  display: grid;
  gap: 9px;
}

.san-panel {
  justify-items: stretch;
}

.san-panel-main {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 12px;
  padding: 12px;
  border: 1px solid var(--drawer-line);
  border-radius: 16px;
  background: rgba(255, 255, 255, 0.46);
  text-align: left;
}

.san-panel-main div {
  display: grid;
}

.san-panel-main strong {
  color: var(--drawer-text);
  font-size: 20px;
}

.san-panel-main span {
  color: rgba(32, 49, 58, 0.62);
  font-family:
    ui-sans-serif,
    'Microsoft YaHei',
    sans-serif;
  font-size: 12px;
}

.san-panel > p {
  padding: 0 4px;
  color: rgba(32, 49, 58, 0.72);
}

.san-scale {
  display: grid;
  gap: 7px;
}

.san-scale-row {
  display: grid;
  grid-template-columns: auto minmax(0, 1fr) auto;
  gap: 8px;
  align-items: center;
  min-height: 38px;
  padding: 8px 10px;
  border: 1px solid var(--drawer-line);
  border-radius: 12px;
  background: rgba(255, 255, 255, 0.42);
}

.san-scale-row.is-current {
  border-color: color-mix(in srgb, var(--accent) 42%, var(--drawer-line));
  background: color-mix(in srgb, var(--accent) 12%, rgba(255, 255, 255, 0.55));
}

.san-scale-row strong {
  color: var(--drawer-text);
}

.san-scale-row small {
  color: rgba(32, 49, 58, 0.58);
  font-family:
    ui-sans-serif,
    'Microsoft YaHei',
    sans-serif;
}

.scale-dot {
  width: 9px;
  height: 9px;
  border-radius: 50%;
  background: var(--icon-blue);
  box-shadow: 0 0 8px color-mix(in srgb, var(--icon-blue) 54%, transparent);
}

.scale-dot.amber {
  background: var(--icon-amber);
  box-shadow: 0 0 8px color-mix(in srgb, var(--icon-amber) 54%, transparent);
}

.scale-dot.danger {
  background: var(--icon-danger);
  box-shadow: 0 0 8px color-mix(in srgb, var(--icon-danger) 54%, transparent);
}

.modal-layer {
  position: absolute;
  inset: 0;
  display: grid;
  align-items: end;
  padding: 14px;
  background: rgba(3, 12, 16, 0.58);
  backdrop-filter: blur(5px);
}

.equipment-modal {
  max-height: min(580px, 136vw);
  overflow: auto;
  border-radius: 22px;
  color: var(--drawer-text);
  background: var(--drawer-bg);
  box-shadow: 0 20px 48px rgba(0, 0, 0, 0.42);
}

.equipment-list {
  display: grid;
  gap: 10px;
  padding: 0 14px 14px;
}

.equipment-footer {
  padding: 0 14px 14px;
}

.equipment-item {
  display: grid;
  grid-template-columns: auto minmax(0, 1fr);
  gap: 10px;
  padding: 12px;
  border: 1px solid var(--drawer-line);
  border-radius: 15px;
  background: rgba(255, 255, 255, 0.56);
}

.equipment-item strong {
  display: block;
  margin-bottom: 4px;
  color: var(--drawer-text);
}

.equipment-item p,
.equipment-item span {
  color: rgba(32, 49, 58, 0.72);
}

.equipment-item span {
  display: inline-block;
  margin-top: 7px;
  padding: 3px 8px;
  border-radius: 999px;
  background: rgba(103, 183, 247, 0.16);
}

.panel-slide-enter-active,
.panel-slide-leave-active,
.modal-fade-enter-active,
.modal-fade-leave-active {
  transition:
    opacity 0.22s ease,
    transform 0.22s ease;
}

.panel-slide-enter-from,
.panel-slide-leave-to {
  opacity: 0;
  transform: translateY(12px);
}

.modal-fade-enter-from,
.modal-fade-leave-to {
  opacity: 0;
}

@keyframes sanPulse {
  0%,
  100% {
    box-shadow:
      inset 0 1px 0 rgba(255, 255, 255, 0.12),
      0 0 0 rgba(184, 71, 79, 0);
  }

  50% {
    box-shadow:
      inset 0 1px 0 rgba(255, 255, 255, 0.18),
      0 0 18px color-mix(in srgb, var(--accent) 26%, transparent);
  }
}

@media (max-width: 520px) {
  .status-frame {
    padding: 12px;
    border-radius: 18px;
  }

  .brand-copy h1 {
    font-size: 22px;
  }

  .hero-card {
    grid-template-columns: 1fr;
  }

  .san-readout {
    width: 100%;
    text-align: left;
  }

  .scene-grid {
    grid-template-columns: 1fr 1fr;
  }

  .scene-cell-wide {
    grid-column: span 2;
  }

  .quick-actions,
  .character-list-meta,
  .detail-grid,
  .drawer-action-grid,
  .mobility-support {
    grid-template-columns: 1fr;
  }
}
